use std::convert::TryFrom;

#[derive(Debug, PartialEq)]
struct Color {
    red: u8,
    green: u8,
    blue: u8,
}

impl TryFrom<(i16, i16, i16)> for Color {
    type Error = String;

    fn try_from(tuple: (i16, i16, i16)) -> Result<Self, Self::Error> {
        let (r, g, b) = tuple;
        for &val in &[r, g, b] {
            if val < 0 || val > 255 {
                return Err(format!("Color value {val} is out of range (0-255)"));
            }
        }
        Ok(Color {
            red: r as u8,
            green: g as u8,
            blue: b as u8,
        })
    }
}

fn main() {
    let c1 = Color::try_from((255, 128, 0));
    println!("{:?}", c1);
    assert!(c1.is_ok());

    let c2 = Color::try_from((-1, 128, 0));
    println!("{:?}", c2);
    assert!(c2.is_err());

    let c3 = Color::try_from((256, 0, 0));
    println!("{:?}", c3);
    assert!(c3.is_err());
}
